mapper.select:
SELECT id,
       request_id,
       trace_id,
       actor_type,
       operator_user_id,
       operator_username,
       operator_role_code,
       actor_department_id,
       action_code,
       resource_type,
       resource_id,
       patient_user_id,
       encounter_id,
       success_flag,
       error_code,
       error_message,
       client_ip,
       user_agent,
       reason_text,
       occurred_at,
       created_at
FROM audit.audit_event
WHERE 1 = 1

    AND occurred_at >= #{from}


    AND occurred_at <= #{to}


    AND action_code = #{actionCode}


    AND operator_user_id = #{operatorUserId}


    AND patient_user_id = #{patientUserId}


    AND encounter_id = #{encounterId}


    AND resource_type = #{resourceType}


    AND resource_id = #{resourceId}


    AND success_flag = #{successFlag}


    AND request_id = #{requestId}

ORDER BY occurred_at DESC, id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM audit.audit_event
WHERE 1 = 1

    AND occurred_at >= #{from}


    AND occurred_at <= #{to}


    AND action_code = #{actionCode}


    AND operator_user_id = #{operatorUserId}


    AND patient_user_id = #{patientUserId}


    AND encounter_id = #{encounterId}


    AND resource_type = #{resourceType}


    AND resource_id = #{resourceId}


    AND success_flag = #{successFlag}


    AND request_id = #{requestId}
